#include <stdio.h>
#include <stdlib.h>

int main(){
    int T; if(scanf("%d", &T)!=1) return 0;
    while(T--){
        int N, A; long long B; scanf("%d %d %lld", &N, &A, &B);
        long long *h = (long long*)malloc(N*sizeof(long long));
        long long low=0, high=0;
        for(int i=0;i<N;i++){
            scanf("%lld", &h[i]);
            if(h[i]>low) low=h[i];
            high+=h[i];
        }
        long long ans=high;
        while(low<=high){
            long long mid = low + (high-low)/2;
            int painters=1; long long cur=0;
            for(int i=0;i<N;i++){
                if(cur + h[i] > mid){
                    painters++; cur = h[i];
                }else cur += h[i];
            }
            if(painters <= A){ ans = mid; high = mid-1; }
            else low = mid+1;
        }
        printf("%lld\n", ans*B);
        free(h);
    }
    return 0;
}

