import sys

def solve():
    data = list(map(int, sys.stdin.read().strip().split()))
    if not data:
        return
    it = iter(data)
    T = next(it)
    out_lines = []
    for _ in range(T):
        N = next(it); A = next(it); B = next(it)
        heights = [next(it) for _ in range(N)]
        low = max(heights)
        high = sum(heights)
        ans = high
        while low <= high:
            mid = (low + high) // 2
            painters = 1
            cur = 0
            for h in heights:
                if cur + h > mid:
                    painters += 1
                    cur = h
                else:
                    cur += h
            if painters <= A:
                ans = mid
                high = mid - 1
            else:
                low = mid + 1
        out_lines.append(str(ans * B))
    sys.stdout.write('\n'.join(out_lines))

if __name__ == "__main__":
    solve()

